# Create a joiner workflow for Engineering new hires
# Triggers 2 days before employeeHireDate, scoped to Engineering department
# Requires LifecycleWorkflows.ReadWrite.All
$workflow = @{
    displayName = 'Engineering new hire onboarding'
    description = 'Generates TAP, adds to groups, enables account 2 days before hire'
    category    = 'joiner'
    isEnabled   = $true
    isSchedulingEnabled = $true
    executionConditions = @{
        '@odata.type' = '#microsoft.graph.identityGovernance.triggerAndScopeBasedConditions'
        scope = @{
            '@odata.type' = '#microsoft.graph.identityGovernance.ruleBasedSubjectSet'
            rule = "(department eq 'Engineering')"
        }
        trigger = @{
            '@odata.type'      = '#microsoft.graph.identityGovernance.timeBasedAttributeTrigger'
            timeBasedAttribute = 'employeeHireDate'
            offsetInDays       = -2
        }
    }
    tasks = @(
        @{
            displayName      = 'Generate TAP'
            category         = 'joiner'
            taskDefinitionId = '1b555e50-7f65-41d5-b514-5894a026d10d'
            isEnabled        = $true
            arguments = @(
                @{ name = 'tapLifetimeMinutes'; value = '480' },
                @{ name = 'requireMultifactorAuthentication'; value = 'false' },
                @{ name = 'isUsableOnce'; value = 'true' }
            )
        },
        @{
            displayName      = 'Add to Engineering onboarding group'
            category         = 'joiner'
            taskDefinitionId = '22085229-5809-45e8-97fd-270d28d66910'
            isEnabled        = $true
            arguments = @(
                @{ name = 'groupID'; value = '<engineering-onboarding-group-oid>' }
            )
        },
        @{
            displayName      = 'Enable account on hire date'
            category         = 'joiner'
            taskDefinitionId = '6fc52c9d-398b-4305-9763-15f42c1676fc'
            isEnabled        = $true
            arguments        = @()
        }
    )
} | ConvertTo-Json -Depth 12

$result = Invoke-MgGraphRequest -Method POST \
  -Uri 'https://graph.microsoft.com/v1.0/identityGovernance/lifecycleWorkflows/workflows' \
  -Body $workflow -ContentType 'application/json'
Write-Host "Created workflow: $($result.id)"

# Leaver workflow: fires on employeeLeaveDateTime
$leaver = @{
    displayName = 'Employee offboarding'
    category    = 'leaver'
    isEnabled   = $true
    isSchedulingEnabled = $true
    executionConditions = @{
        '@odata.type' = '#microsoft.graph.identityGovernance.triggerAndScopeBasedConditions'
        scope = @{
            '@odata.type' = '#microsoft.graph.identityGovernance.ruleBasedSubjectSet'
            rule = "(department ne null)"
        }
        trigger = @{
            '@odata.type'      = '#microsoft.graph.identityGovernance.timeBasedAttributeTrigger'
            timeBasedAttribute = 'employeeLeaveDateTime'
            offsetInDays       = 0
        }
    }
    tasks = @(
        @{
            displayName      = 'Disable account'
            taskDefinitionId = '1dfdfcc7-52fa-4c2e-bf3a-e3919cc12950'
            isEnabled        = $true; arguments = @()
        },
        @{
            displayName      = 'Revoke sign-in sessions'
            taskDefinitionId = 'b553aa85-59d5-4bcd-a7c3-d2ec9518b0a6'
            isEnabled        = $true; arguments = @()
        },
        @{
            displayName      = 'Remove from all groups'
            taskDefinitionId = '1ec10b91-4b5a-4f30-81fb-4b3b7a5a1a6d'
            isEnabled        = $true; arguments = @()
        },
        @{
            displayName      = 'Remove all access packages'
            taskDefinitionId = '4a0b64f2-c7ec-46ba-b117-18f262946c50'
            isEnabled        = $true; arguments = @()
        }
    )
} | ConvertTo-Json -Depth 10

Invoke-MgGraphRequest -Method POST \
  -Uri 'https://graph.microsoft.com/v1.0/identityGovernance/lifecycleWorkflows/workflows' \
  -Body $leaver -ContentType 'application/json'

# Step 1: Register a custom extension (Logic App endpoint)
$extBody = @{
    displayName = 'Onboarding badge request'
    description = 'Creates badge access request in physical security system'
    endpointConfiguration = @{
        '@odata.type'  = '#microsoft.graph.logicAppTriggerEndpointConfiguration'
        subscriptionId = '<azure-subscription-id>'
        resourceGroupName = '<rg-name>'
        logicAppWorkflowName = 'lapp-onboarding-badge'
    }
    clientConfiguration = @{
        '@odata.type'        = '#microsoft.graph.customExtensionClientConfiguration'
        timeoutInMilliseconds = 5000
        maximumRetries       = 3
    }
    authenticationConfiguration = @{
        '@odata.type' = '#microsoft.graph.azureAdPopTokenAuthentication'
    }
} | ConvertTo-Json -Depth 8

$ext = Invoke-MgGraphRequest -Method POST \
  -Uri 'https://graph.microsoft.com/v1.0/identityGovernance/lifecycleWorkflows/customTaskExtensions' \
  -Body $extBody -ContentType 'application/json'

# Step 2: Reference the extension in a workflow task
@{
    displayName      = 'Call badge system Logic App'
    taskDefinitionId = 'adb4ef7a-0d4f-4071-8ebf-d3b0a5a12c1a'
    isEnabled        = $true
    arguments = @(
        @{ name = 'CustomTaskExtensionID'; value = $ext.id }
    )
}
